from flask import Flask, jsonify, request, g
from flask_jwt_extended import jwt_required, get_jwt_identity

app = Flask(__name__)

# Dummy user database for demonstration purposes
users_db = {
    'user1': {'username': 'john_doe', 'email': 'john@example.com', 'account_type': 'basic', 'credits': 100, 'referral_code': 'J1234', 'verified_status': False},
    # Add more users as needed
}

@app.route('/update_profile', methods=['PUT'])
@jwt_required()
def update_profile():
    current_user_id = get_jwt_identity()
    user = users_db.get(current_user_id)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    # Get data from request
    data = request.json
    allowed_fields = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']

    for field in allowed_fields:
        if field in data:
            user[field] = data[field]

    users_db[current_user_id] = user
    return jsonify({'message': 'Profile updated successfully', 'user': user}), 200

if __name__ == '__main__':
    app.run(debug=True)